pub mod error;
pub mod globals;
pub mod r#type;
pub mod value;

use num_enum::TryFromPrimitive;

use crate::{
    compiler::{
        chunk::Chunk,
        constants::Constant,
        instruction::{Instruction, OpCode},
    },
    source::Spanned,
    vm::{error::Result, globals::Globals, value::Value},
};

/// Whether instruction tracking is enabled or not.
pub const DEBUG_INSTRUCTION_TRACKING: bool = false;

/// Executes bytecode generated by the [`compiler`] in [`Chunk`] format.
pub struct VM {
    /// The index to the instruction currently being executed, also known as the instruction
    /// pointer.
    ip: usize,

    /// The mapping of all declared global variables.
    pub(crate) globals: Globals,

    /// The runtime stack of values being accumulated.
    stack: Vec<Value>,
}

impl VM {
    /// Creates a new virtual machine, but does not begin program execution.
    pub fn new() -> Self {
        Self {
            ip: 0,
            globals: Globals::new(),
            stack: Vec::new(),
        }
    }

    /// Executes the provided [`Chunk`] until program termination.
    pub fn execute(&mut self, chunk: &Chunk) -> Result<Option<Value>> {
        self.ip = 0;
        self.stack = Vec::with_capacity(128);

        loop {
            if DEBUG_INSTRUCTION_TRACKING {
                println!("\n=== instruction dump ===");
                println!("ip:          {}", self.ip);
                println!(
                    "instruction: {:?}",
                    Instruction::decode(&chunk.code, self.ip).0
                );
                println!("stack:       {:?}", self.stack);
                println!("globals:     {:?}", self.globals);
                println!("========================\n");
            }

            let opcode = OpCode::try_from_primitive(self.read_byte(chunk)).unwrap();

            match opcode {
                OpCode::Return => {
                    return Ok(self.stack.pop());
                }

                OpCode::Duplicate => {
                    let top = self.stack.last().unwrap().clone();
                    self.stack.push(top);
                }

                OpCode::Pop => {
                    let _ = self.pop_stack();
                }

                OpCode::Jump => {
                    let offset = i16::from_ne_bytes([self.read_byte(chunk), self.read_byte(chunk)]);
                    self.ip = self.ip.saturating_add_signed(offset as isize);
                }

                OpCode::JumpIfTrue => {
                    let offset = i16::from_ne_bytes([self.read_byte(chunk), self.read_byte(chunk)]);

                    if self.pop_stack().is_truthy() {
                        self.ip = self.ip.saturating_add_signed(offset as isize);
                    }
                }

                OpCode::JumpIfFalse => {
                    let offset = i16::from_ne_bytes([self.read_byte(chunk), self.read_byte(chunk)]);

                    if !self.pop_stack().is_truthy() {
                        self.ip = self.ip.saturating_add_signed(offset as isize);
                    }
                }

                OpCode::LoadConstant => {
                    let constant = chunk.constants[self.read_byte(chunk)];
                    self.stack.push(Value::from(constant));
                }

                OpCode::DefineGlobal => {
                    let Constant::Symbol(name) = chunk.constants[self.read_byte(chunk)] else {
                        panic!("index into constant pool for global was not a symbol");
                    };

                    let value = self.pop_stack();

                    self.globals.runtime.insert(name, value);
                }

                OpCode::GetGlobal => {
                    let Constant::Symbol(name) = chunk.constants[self.read_byte(chunk)] else {
                        panic!("index into constant pool for global was not a symbol");
                    };

                    let value = self
                        .globals
                        .runtime
                        .get(&name)
                        .expect("unbound global should have been caught by compiler")
                        .clone();

                    self.stack.push(value);
                }

                OpCode::SetGlobal => {
                    let Constant::Symbol(name) = chunk.constants[self.read_byte(chunk)] else {
                        panic!("index into constant pool for global was not a symbol");
                    };

                    let value = self.pop_stack().clone();
                    self.globals.runtime.insert(name, value);
                }

                OpCode::GetLocal => {
                    let index = self.read_byte(chunk) as usize;
                    let value = self.stack[index].clone();
                    self.stack.push(value);
                }

                OpCode::SetLocal => {
                    let index = self.read_byte(chunk) as usize;
                    let value = self.pop_stack().clone();
                    self.stack[index] = value;
                }

                OpCode::Print => {
                    let value = self.pop_stack();
                    println!("{value}");
                }

                OpCode::Add
                | OpCode::Subtract
                | OpCode::Multiply
                | OpCode::Divide
                | OpCode::Equals
                | OpCode::LessThan
                | OpCode::LessThanEquals => {
                    self.handle_binary_operation(chunk, opcode)?;
                }

                OpCode::Negate | OpCode::Not => self.handle_unary_operation(chunk, opcode)?,
            }
        }
    }

    /// Handles a non shortcircuiting binary instruction.
    fn handle_binary_operation(&mut self, chunk: &Chunk, opcode: OpCode) -> Result<()> {
        let rhs = self.pop_stack();
        let lhs = self.pop_stack();

        let reducer = match opcode {
            OpCode::Add => Value::add,
            OpCode::Subtract => Value::subtract,
            OpCode::Multiply => Value::multiply,
            OpCode::Divide => Value::divide,
            OpCode::Equals => Value::equals,
            OpCode::LessThan => Value::less_than,
            OpCode::LessThanEquals => Value::less_than_equals,
            _ => unreachable!("called handle_binary_operation with non binary opcode"),
        };

        let span = chunk.span_at(self.ip - 1);

        self.stack
            .push(reducer(lhs, rhs).map_err(|e| Spanned::wrap(e, span))?);

        Ok(())
    }

    /// Handles a unary instruction.
    fn handle_unary_operation(&mut self, chunk: &Chunk, opcode: OpCode) -> Result<()> {
        let operand = self.pop_stack();

        let reducer = match opcode {
            OpCode::Negate => Value::negate,
            OpCode::Not => Value::not,
            _ => unreachable!("called handle_unary_operation with non unary opcode"),
        };

        let span = chunk.span_at(self.ip - 1);

        self.stack
            .push(reducer(operand).map_err(|e| Spanned::wrap(e, span))?);

        Ok(())
    }

    /// Pops a value from the top of the stack.
    fn pop_stack(&mut self) -> Value {
        self.stack
            .pop()
            .expect("should never encounted a stack underflow")
    }

    /// Reads one byte from the [`Chunk::code`], advancing the instruction pointer by one byte.
    fn read_byte(&mut self, chunk: &Chunk) -> u8 {
        let value = chunk.code[self.ip];
        self.ip += 1;
        value
    }
}
